import{_ as d,o as e,c as a,a5 as o}from"./chunks/framework.D9Kapg2s.js";const s="/assets/local-home.png.Dq05Daz1.png",i="/assets/ai-backend.Ct5kgG78.png",k=JSON.parse('{"title":"快速开始 · Web","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/getting-started.md","filePath":"zh/guide/getting-started.md"}'),r={name:"zh/guide/getting-started.md"};function l(c,t,n,h,p,g){return e(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="快速开始-·-web" tabindex="-1">快速开始 · Web <a class="header-anchor" href="#快速开始-·-web" aria-label="Permalink to &quot;快速开始 · Web&quot;">​</a></h1><p>目标：在约 5 分钟内完成 <strong>第一次成功翻译</strong>——从启动界面到看到一段可用译文。</p><p>本页只走 <strong>最短路径</strong>。术语提取、质量裁决、多轮流水线等见后文「下一步」。</p><div class="tip custom-block"><p class="custom-block-title">推荐方式</p><p>个人使用优先 <strong>预编译二进制 + 本地模式</strong>：免登录、数据在本机、启动后自动打开浏览器（<code>http://127.0.0.1:18080</code>）。</p></div><h2 id="_1-安装并启动" tabindex="-1">1. 安装并启动 <a class="header-anchor" href="#_1-安装并启动" aria-label="Permalink to &quot;1. 安装并启动&quot;">​</a></h2><h3 id="方式-a-预编译二进制-推荐" tabindex="-1">方式 A：预编译二进制（推荐） <a class="header-anchor" href="#方式-a-预编译二进制-推荐" aria-label="Permalink to &quot;方式 A：预编译二进制（推荐）&quot;">​</a></h3><ol><li>打开 <a href="https://github.com/MeowSalty/LinguaFlow/releases" target="_blank" rel="noreferrer">GitHub Releases</a>，下载对应平台的压缩包</li><li>解压后运行：</li></ol><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-NA-Pe" id="tab-KQq59qr" checked><label data-title="Linux / macOS" for="tab-KQq59qr">Linux / macOS</label><input type="radio" name="group-NA-Pe" id="tab-TBcJ9Kk"><label data-title="Windows" for="tab-TBcJ9Kk">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> linguaflow</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./linguaflow</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 资源管理器中双击 linguaflow.exe</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或在终端：</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">linguaflow.exe</span></span></code></pre></div></div></div><p>浏览器应自动打开 <strong>本地模式</strong> 界面：<code>http://127.0.0.1:18080</code>（若端口被占用会自动尝试后续端口）。</p><p><img src="`+s+`" alt="本地模式主界面"></p><div class="tip custom-block"><p class="custom-block-title">本步成功标准</p><p>浏览器能打开 LinguaFlow 界面，且无需登录即可进入主页面（本地模式）。</p></div><h3 id="方式-b-docker" tabindex="-1">方式 B：Docker <a class="header-anchor" href="#方式-b-docker" aria-label="Permalink to &quot;方式 B：Docker&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ghcr.io/meowsalty/linguaflow:latest</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 8080:8080</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ghcr.io/meowsalty/linguaflow:latest</span></span></code></pre></div><p>在浏览器打开 <code>http://localhost:8080</code>。</p><div class="warning custom-block"><p class="custom-block-title">Docker 与二进制行为不同</p><table tabindex="0"><thead><tr><th></th><th>二进制 / 源码双击</th><th>Docker 默认</th></tr></thead><tbody><tr><td>模式</td><td><strong>本地模式</strong>（免登录）</td><td><strong>服务器模式</strong>（需注册/登录）</td></tr><tr><td>端口</td><td><code>18080</code></td><td><code>8080</code></td></tr><tr><td>适用</td><td>个人本机</td><td>容器部署、联调</td></tr></tbody></table><p>服务器模式仍在完善中，仅建议试用。详见 <a href="/zh/guide/modes.html">使用模式</a>。</p></div><h3 id="方式-c-从源码构建" tabindex="-1">方式 C：从源码构建 <a class="header-anchor" href="#方式-c-从源码构建" aria-label="Permalink to &quot;方式 C：从源码构建&quot;">​</a></h3><p>需要 Go、Node.js、pnpm 与 <a href="https://taskfile.dev" target="_blank" rel="noreferrer">Task</a>。步骤见 <a href="/zh/guide/installation.html#从源码构建">安装部署</a>。</p><hr><h2 id="_2-配置-ai-后端" tabindex="-1">2. 配置 AI 后端 <a class="header-anchor" href="#_2-配置-ai-后端" aria-label="Permalink to &quot;2. 配置 AI 后端&quot;">​</a></h2><p>翻译依赖你自己的 AI API Key，服务不会内置密钥。</p><ol><li><p>打开顶部导航 <strong>AI 后端</strong></p></li><li><p>点击 <strong>添加后端</strong></p></li><li><p>选择提供商并填写：</p><table tabindex="0"><thead><tr><th>提供商</th><th>类型</th><th>常用默认模型</th></tr></thead><tbody><tr><td>OpenAI</td><td><code>openai</code></td><td><code>gpt-4o-mini</code></td></tr><tr><td>Anthropic</td><td><code>anthropic</code></td><td><code>claude-sonnet-4-5</code></td></tr><tr><td>Google Gemini</td><td><code>google</code></td><td><code>gemini-2.5-flash</code></td></tr></tbody></table></li><li><p>填入 <strong>API Key</strong>（必填）</p></li><li><p>如需代理或本地模型（Ollama、LM Studio、Azure 等），填写兼容的 <strong>Base URL</strong></p></li><li><p>保存</p></li></ol><p><img src="`+i+'" alt="添加 AI 后端"></p><div class="tip custom-block"><p class="custom-block-title">本地模型</p><p>OpenAI 类型可对接 OpenAI 兼容接口，例如 Ollama：<code>http://localhost:11434/v1</code>。部分网关仅接受流式请求时，在后端选项中开启 <strong>流式请求</strong>。</p></div><div class="tip custom-block"><p class="custom-block-title">本步成功标准</p><p>「AI 后端」列表中能看到刚添加的条目，状态可用。</p></div><hr><h2 id="_3-创建最简执行计划" tabindex="-1">3. 创建最简执行计划 <a class="header-anchor" href="#_3-创建最简执行计划" aria-label="Permalink to &quot;3. 创建最简执行计划&quot;">​</a></h2><p>执行计划 =「用哪个后端、按什么策略翻译」。内置有通用提示词与策略，但计划需要你关联自己的后端。</p><ol><li><p>打开 <strong>翻译配置 → 执行计划</strong>（或设置中的执行计划入口）</p></li><li><p>点击 <strong>创建计划</strong></p></li><li><p>名称例如：<code>默认翻译</code></p></li><li><p>只添加 <strong>一轮翻译</strong>，其余可先不管：</p><table tabindex="0"><thead><tr><th>项</th><th>建议</th></tr></thead><tbody><tr><td>模式</td><td><strong>翻译</strong></td></tr><tr><td>后端</td><td>上一步创建的后端</td></tr><tr><td>提示词模板</td><td>内置 <strong>通用提示词</strong></td></tr><tr><td>执行配置</td><td>内置 <strong>通用策略</strong></td></tr><tr><td>批次大小 / 字数</td><td>见下方「批次怎么设」</td></tr><tr><td>并发</td><td>先用 <code>2</code>～<code>4</code>；若频繁 429 再降</td></tr></tbody></table></li><li><p><strong>不要</strong>在第一次就加术语提取、质量裁决等多轮（等跑通后再加）</p></li><li><p>保存</p></li></ol><h3 id="批次怎么设" tabindex="-1">批次怎么设 <a class="header-anchor" href="#批次怎么设" aria-label="Permalink to &quot;批次怎么设&quot;">​</a></h3><p>产品内置/模板里常见默认是 <strong><code>batch_size: 1</code></strong>（一次只译一段），这是为了<strong>稳</strong>，不是因为模型只能吃那么少。</p><table tabindex="0"><thead><tr><th>场景</th><th>更贴近现状的起点</th><th>说明</th></tr></thead><tbody><tr><td>第一次跑通、排错</td><td><code>batch_size = 1</code></td><td>失败好定位，与内置默认一致</td></tr><tr><td>短段多（字幕、列表、UI 文案）</td><td><code>batch_size = 8</code>～<code>20</code>，或主要靠字数</td><td>段短，多段合批能明显减少请求次数</td></tr><tr><td>中等段落（普通 Markdown）</td><td><code>batch_size = 4</code>～<code>10</code></td><td>多数 128k+ 模型足够；再观察失败率</td></tr><tr><td>长段、结构复杂（大表、长 HTML 块）</td><td><code>batch_size</code> 保持小，或 <strong><code>max_words_per_batch</code></strong></td><td>单段本身就可能很长</td></tr><tr><td>推荐稳态（通用）</td><td><strong><code>batch_size</code> 作软上限 + <code>max_words_per_batch</code></strong></td><td>例如段数 <code>10</code> + 字词 <code>1500</code>～<code>3000</code>（按模型与语言调）</td></tr></tbody></table><p><strong>要不要用字数？建议要。</strong> 系统支持双重约束（段落数 <strong>且</strong> 字词数，任一触顶就切批）：</p><ul><li>只设 <code>batch_size</code>：10 段短字幕很轻松，10 段长文可能一次塞爆输出或 JSON</li><li>只设 / 同时设 <code>max_words_per_batch</code>：按源文字词量打包，长短不一的文档更稳</li></ul><p>字词统计规则：CJK 大致按字计，其它语言按空白分词（与代码中 <code>CountWords</code> 一致）。<br> 上下文窗口大，不等于「一批越大越好」——还要留出：<strong>系统提示词、术语表、前后文、结构化 JSON 协议，以及译文输出长度</strong>。批次过大时更常见的是解析失败、漏段、占位符损坏，而不只是「上下文不够」。失败时流水线会按 <code>fallback_shrink</code> 自动缩小批次重试，但起点过大仍会浪费请求。</p><div class="tip custom-block"><p class="custom-block-title">成功标准（本步）</p><p>计划列表中能看到刚建的计划，且其中至少有一轮绑定了你的后端。</p></div><hr><h2 id="_4-创建项目并上传文件" tabindex="-1">4. 创建项目并上传文件 <a class="header-anchor" href="#_4-创建项目并上传文件" aria-label="Permalink to &quot;4. 创建项目并上传文件&quot;">​</a></h2><ol><li><p>打开 <strong>项目</strong> → <strong>新建项目</strong></p></li><li><p>填写：</p><table tabindex="0"><thead><tr><th>字段</th><th>建议</th></tr></thead><tbody><tr><td>项目名称</td><td>任意，如 <code>试用</code></td></tr><tr><td>源语言</td><td><code>auto</code> 或明确语言</td></tr><tr><td>目标语言</td><td>如简体中文</td></tr></tbody></table></li><li><p>进入项目工作区 → <strong>资源</strong> 标签</p></li><li><p>上传一个小文件试水，例如：</p><ul><li>一篇短 Markdown（<code>.md</code>）</li><li>或一小段字幕（<code>.srt</code>）</li></ul></li></ol><p>等待解析完成（资源列表出现该文件即可）。</p><blockquote><p><strong>界面示意（占位）</strong> · 项目工作区 · 资源<br> 资源列表显示文件名、格式与解析状态；支持拖拽上传。顶部有项目语言方向与统计。<br><em>待补截图：<code>docs/public/images/workspace-resources.png</code></em></p></blockquote><p>支持的格式一览见 <a href="/zh/guide/formats.html">格式支持</a>。</p><div class="tip custom-block"><p class="custom-block-title">本步成功标准</p><p>项目列表中有项目；工作区「资源」中出现已解析的文件。</p></div><hr><h2 id="_5-开始翻译并查看结果" tabindex="-1">5. 开始翻译并查看结果 <a class="header-anchor" href="#_5-开始翻译并查看结果" aria-label="Permalink to &quot;5. 开始翻译并查看结果&quot;">​</a></h2><ol><li>在资源列表选中刚上传的文件</li><li>点击 <strong>翻译</strong></li><li>在面板中选择第 3 步的执行计划</li><li>其余选项可保持默认（首次不必开「自动审批」）</li><li>点击 <strong>开始翻译</strong></li><li>在 <strong>作业</strong> 标签查看进度；完成后打开 <strong>段落</strong> 标签查看原文与译文</li></ol><blockquote><p><strong>界面示意（占位）</strong> · 作业进度与段落结果<br> 「作业」标签显示进度 / ETA；完成后在「段落」中左右对照原文与译文。<br><em>待补截图：<code>docs/public/images/job-and-segments.png</code></em></p></blockquote><div class="tip custom-block"><p class="custom-block-title">第一次成功的标志（请逐项确认）</p><table tabindex="0"><thead><tr><th>#</th><th>标志</th><th>在哪里看</th></tr></thead><tbody><tr><td>1</td><td>作业状态为 <strong>已完成</strong>（或大部分段落已翻译）</td><td>工作区 → <strong>作业</strong></td></tr><tr><td>2</td><td>段落列表中能看到 <strong>译文</strong></td><td>工作区 → <strong>段落</strong></td></tr><tr><td>3</td><td>能对某一段 <strong>编辑 / 审批</strong></td><td>段落行内操作</td></tr><tr><td>4</td><td>（可选）能 <strong>下载</strong> 翻译结果文件</td><td>资源页下载</td></tr></tbody></table><p>若作业失败，先看作业错误信息，并对照 <a href="/zh/guide/faq.html">常见问题</a>（API Key、限速、端口、执行计划等）。</p></div><h2 id="常用支持格式-速查" tabindex="-1">常用支持格式（速查） <a class="header-anchor" href="#常用支持格式-速查" aria-label="Permalink to &quot;常用支持格式（速查）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>扩展名</th></tr></thead><tbody><tr><td>文档</td><td><code>.md</code> / <code>.markdown</code> / <code>.mdx</code>、<code>.html</code>、<code>.docx</code>、<code>.txt</code></td></tr><tr><td>电子书</td><td><code>.epub</code></td></tr><tr><td>字幕</td><td><code>.srt</code> / <code>.vtt</code> / <code>.ass</code></td></tr><tr><td>结构化</td><td><code>.json</code> / <code>.yaml</code> / <code>.yml</code> / <code>.toml</code></td></tr></tbody></table><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>跑通最短路径后，按需深入：</p><table tabindex="0"><thead><tr><th>目标</th><th>文档</th></tr></thead><tbody><tr><td>弄清项目 / 资源 / 作业 / 计划</td><td><a href="/zh/guide/concepts.html">核心概念</a></td></tr><tr><td>终端批量翻译、CI 集成</td><td><a href="/zh/guide/cli-quickstart.html">快速开始 · CLI</a></td></tr><tr><td>术语表、自动提取</td><td><a href="/zh/guide/glossary.html">术语表管理</a></td></tr><tr><td>审校、质检、筛选</td><td><a href="/zh/guide/review.html">翻译审校</a></td></tr><tr><td>多轮计划、质量裁决、保护规则</td><td><a href="/zh/guide/translation-config.html">翻译配置 · 使用</a> · <a href="/zh/guide/pipeline.html">流水线与原理</a></td></tr><tr><td>安装细节、Docker Compose、数据目录</td><td><a href="/zh/guide/installation.html">安装部署</a></td></tr><tr><td>本地模式 vs 服务器模式</td><td><a href="/zh/guide/modes.html">使用模式</a></td></tr></tbody></table>',53)])])}const u=d(r,[["render",l]]);export{k as __pageData,u as default};
